import React, { useState } from 'react';
import './Register.css';
function Register() {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [status, setStatus] = useState({ msg: "", type: "" }); 

  const handleRegister = async (e) => {
    e.preventDefault();
    setStatus({ msg: "Отправка...", type: "" });

    try {
      const response = await fetch("http://localhost:3000/api/register", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ username, password })
      });

      if (response.ok) {
        const data = await response.json();
        setStatus({ msg: "Регистрация успешна! Добро пожаловать.", type: "success" });
        setUsername(""); setPassword("");
      } else {
        setStatus({ msg: "Ошибка сервера: " + response.status, type: "error" });
      }
    } catch (err) {
      setStatus({ msg: "Сервер Семисвинофф не отвечает. Проверь консоль бэкенда!", type: "error" });
    }
  };

  return (
    <div className="register-page">
      <div className="register-card">
        <h2>Регистрация</h2>
        <form onSubmit={handleRegister} className="reg-form">
          <input 
            type="text" 
            placeholder="Придумайте логин" 
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            required 
          />
          <input 
            type="password" 
            placeholder="Ваш секретный пароль" 
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required 
          />
          <button type="submit" className="btn-red">Стать своим</button>
        </form>
        
        {status.msg && (
          <div className={`status-msg ${status.type}`}>
            {status.msg}
          </div>
        )}
      </div>
    </div>
  );
}

export default Register;
